import { Injectable } from '@nestjs/common';

import { StyleCopurchaseModel } from '@modules/db/style-copurchases/models/style-copurchase.model';

import { LogExecution } from '@decorators/log-execution.decorator';

@Injectable()
export class StyleCopurchasesService {
	constructor(private readonly styleCopurchaseModel: StyleCopurchaseModel) {}

	@LogExecution({
		paramFormatter: ([{ styleId, limit, excludeIds }]: [
			{
				styleId: number;
				limit?: number;
				excludeIds?: number[];
			},
		]) => ({
			styleId,
			limit,
			excludeCount: excludeIds?.length ?? 0,
		}),
		responseFormatter: (
			res: { paired_style_id: number; copurchase_count: number }[],
		) => ({
			count: res.length,
		}),
	})
	async getTopCopurchases({
		styleId,
		limit = 4,
		excludeIds = [],
	}: {
		styleId: number;
		limit?: number;
		excludeIds?: number[];
	}): Promise<{ paired_style_id: number; copurchase_count: number }[]> {
		return this.styleCopurchaseModel.findTopCopurchases({
			styleId,
			limit,
			excludeIds,
		});
	}

	@LogExecution({
		paramFormatter: ([
			{ styleId, limit, excludeIds, diversifyCategories, favorOppositeType },
		]: [
			{
				styleId: number;
				limit?: number;
				excludeIds?: number[];
				diversifyCategories?: boolean;
				favorOppositeType?: boolean;
				seedStyleType?: string | null | undefined;
			},
		]) => ({
			styleId,
			limit,
			excludeCount: excludeIds?.length ?? 0,
			diversifyCategories,
			favorOppositeType,
		}),
		responseFormatter: (res: unknown[]) => ({
			count: res.length,
		}),
	})
	async getTopCopurchasesDiversified({
		styleId,
		limit = 4,
		excludeIds = [],
		diversifyCategories = false,
		favorOppositeType = false,
		seedStyleType,
	}: {
		styleId: number;
		limit?: number;
		excludeIds?: number[];
		diversifyCategories?: boolean;
		favorOppositeType?: boolean;
		seedStyleType?: string | null | undefined;
	}): Promise<
		{
			paired_style_id: number;
			copurchase_count: number;
			primary_category_id: number;
			style_type: string | null;
		}[]
	> {
		return this.styleCopurchaseModel.findTopCopurchasesDiversified({
			styleId,
			limit,
			excludeIds,
			diversifyCategories,
			favorOppositeType,
			seedStyleType,
		});
	}

	@LogExecution({
		paramFormatter: ([{ pairs }]: [
			{
				pairs: { styleIdA: number; styleIdB: number; copurchaseCount: number }[];
			},
		]) => ({
			recordCount: pairs.length,
		}),
		responseFormatter: () => ({ completed: true }),
	})
	async bulkInsert({
		pairs,
	}: {
		pairs: {
			styleIdA: number;
			styleIdB: number;
			copurchaseCount: number;
		}[];
	}): Promise<void> {
		return this.styleCopurchaseModel.bulkInsert({ pairs });
	}

	@LogExecution({
		paramFormatter: () => ({}),
		responseFormatter: () => ({ completed: true }),
	})
	async clearExistingData(): Promise<void> {
		return this.styleCopurchaseModel.clearExistingData();
	}

	@LogExecution({
		paramFormatter: () => ({}),
		responseFormatter: (count: number) => ({ count }),
	})
	async getRecordCount(): Promise<number> {
		return this.styleCopurchaseModel.getRecordCount();
	}
}

